function calcInvoiceTotal(items: Item[]): number {
  const subtotal = items.reduce((s, i) => s + i.price, 0);
  const tax = subtotal * 0.08;
  const fee = subtotal > 100 ? 0 : 5;
  return subtotal + tax + fee;
}

